import {
  polygon, rectangle, ellipse, segment, circle,
  union, dilate, render,
} from '../../src/index.js';

// --- Single destroyer silhouette (parametric — used 5 times) ---
function destroyer(cx, cy, scale = 1.0) {
  const s = scale;
  // Hull: long flat-bottomed with slight bow taper
  const hull = polygon([
    [cx-0.18*s, cy-0.020*s],
    [cx+0.18*s, cy-0.020*s],
    [cx+0.21*s, cy-0.050*s],
    [cx-0.18*s, cy-0.050*s],
  ]);
  // Superstructure: stack of 2 boxes
  const sup1 = rectangle([0.12*s, 0.03*s], [cx-0.02*s, cy+0.000*s]);
  const sup2 = rectangle([0.07*s, 0.03*s], [cx-0.03*s, cy+0.035*s]);
  // Forward gun (small cylinder)
  const gun = circle(0.012*s, [cx+0.13*s, cy-0.010*s]);
  // Mast
  const mast = segment([cx-0.03*s, cy+0.045*s], [cx-0.03*s, cy+0.085*s], 0.004*s);
  return union(hull, sup1, sup2, gun, mast);
}

// --- Fleet of 5 destroyers in echelon formation ---
const d1 = destroyer(-0.55, -0.10, 0.9);
const d2 = destroyer(-0.28, -0.05, 1.0);
const d3 = destroyer( 0.00,  0.00, 1.05);
const d4 = destroyer( 0.28, -0.05, 1.0);
const d5 = destroyer( 0.55, -0.10, 0.9);
const fleet = union(d1, d2, d3, d4, d5);

// Wakes — small white foam ovals trailing aft of each ship
const wake1 = ellipse(0.08, 0.012, [-0.70, -0.13]);
const wake2 = ellipse(0.09, 0.014, [-0.43, -0.08]);
const wake3 = ellipse(0.10, 0.015, [-0.15,  0.00*0]);
const wake4 = ellipse(0.09, 0.014, [ 0.13, -0.08]);
const wake5 = ellipse(0.08, 0.012, [ 0.40, -0.13]);
const wakes = union(wake1, wake2, wake3, wake4, wake5);

const sea  = rectangle([1.6, 0.7], [0, -0.35]);
const sky  = rectangle([1.6, 0.5], [0, 0.35]);

const layers = [
  { sdf: sky,                color: [125, 160, 200] },
  { sdf: sea,                color: [25, 65, 110] },
  { sdf: rectangle([1.6, 0.04], [0, 0.0]), color: [60, 110, 160] },
  { sdf: wakes,              color: [220, 230, 240] },
  { sdf: dilate(fleet, 0.010), color: [20, 25, 35] },
  { sdf: fleet,              color: [85, 92, 105] },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [110, 145, 185], bottom: [190, 215, 230] },
});
```

**Composition notes**: 5 destroyers in echelon formation across the horizon, with the middle ship slightly larger (closer). Each ship has hull + 2-tier superstructure + forward gun + mast — the SAME silhouette repeated 5 times via a `destroyer(cx, cy, scale)` helper. White wake foam trails aft each ship. Sea/sky with subtle horizon highlight band.
